<template>
	<view class="container">
		<view class="box">
			<Mtitle title="Login"></Mtitle>
			<!-- з”ЁжҲ·еҗҚ -->
			<Minput title="User" class="input" placeholder="иҜ·иҫ“е…Ҙз”ЁжҲ·еҗҚ" v-model="username"></Minput>
			<!-- еҜҶз Ғ -->
			<Minput title="Password" class="input" placeholder="иҜ·иҫ“е…Ҙз”ЁжҲ·еҜҶз Ғ" type="password" style="top: 400rpx;"
				v-model="password"></Minput>
			<!-- зҷ»еҪ•жҢүй’® -->
			<view class="btn" @click="handleLogin">
				<Mbutton content="зҷ»еҪ•"></Mbutton>
			</view>

		</view>
	</view>
</template>

<script setup>
	import {
		ref
	} from 'vue'

	const username = ref('')
	const password = ref('')

	const handleLogin = async () => {
		console.log('рҹ“Ө зҷ»еҪ•иҜ·жұӮж•°жҚ®:', {
			username: username.value,
			password: password.value
		})

		if (!username.value || !password.value) {
			uni.showToast({
				title: 'иҜ·иҫ“е…Ҙз”ЁжҲ·еҗҚе’ҢеҜҶз Ғ',
				icon: 'none'
			})
			return
		}

		try {
			const res = await uni.request({
				url: 'http://localhost:5000/api/login/login',
				method: 'POST',
				header: {
					'Content-Type': 'application/json'
				},
				data: {
					username: username.value,
					password: password.value
				}
			})

			const {
				statusCode,
				data
			} = res
			if (statusCode === 200 && data.token) {
				uni.setStorageSync('token', data.token)
				uni.showToast({
					title: 'зҷ»еҪ•жҲҗеҠҹ',
					icon: 'success'
				})
				setTimeout(() => {
					uni.navigateTo({
						url: '/pages/personalPage/personalPage'
					})
				}, 1000)
			} else {
				uni.showToast({
					title: data.message || 'зҷ»еҪ•еӨұиҙҘ',
					icon: 'none'
				})
			}
		} catch (err) {
			console.error('Login error:', err)
			uni.showToast({
				title: 'зҪ‘з»ңй”ҷиҜҜжҲ–жңҚеҠЎеҷЁж— е“Қеә”',
				icon: 'none'
			})
		}
	}
</script>
